fix:
private String getRemainingJSDocLine() {
  String remainingString = stream.getRemainingJSDocLine().trim();
  if(remainingString.startsWith("{") && !remainingString.endsWith("}")){
      while(!remainingString.endsWith("}")) {
          remainingString += " ";
          remainingString += this.stream.read();
      }
  } else {
      int i = 0;
      for (; i < remainingString.length(); ++i) {
          char c = remainingString.charAt(i);
          if (!Character.isWhitespace(c)) break;
      }
      remainingString = remainingString.substring(i).trim();
  }
  return remainingString;
}

